// ============================================================
// RENDER — PRODUCTS PAGE (products.html)
// Renders category filter + product grid
// ============================================================
function renderProductsPage() {
  const filtersEl = document.getElementById('product-filters');
  const gridEl    = document.getElementById('products-grid');
  const countEl   = document.getElementById('product-count');
  if (!filtersEl || !gridEl) return;

  let activeFilter = 'all';

  // Build flat products list with category reference
  function getAllProducts() {
    const items = [];
    SHOP_DATA.categories.forEach(cat => {
      if (cat.products && cat.products.length) {
        cat.products.forEach(p => items.push({ ...p, categoryId: cat.id, categoryName: cat.name }));
      } else {
        // Show category placeholder card when no products listed yet
        items.push({
          id          : `cat-${cat.id}`,
          title       : cat.name,
          price       : `Starting ${cat.priceRange}`,
          badge       : '',
          categoryId  : cat.id,
          categoryName: cat.name,
          isPlaceholder: true,
          icon        : cat.icon,
          imgClass    : cat.imgClass,
          description : cat.description,
        });
      }
    });
    return items;
  }

  function renderGrid(filter) {
    const all = getAllProducts();
    const filtered = filter === 'all'
      ? all
      : all.filter(p => p.categoryId === filter);

    if (countEl) countEl.textContent = filtered.length;

    if (!filtered.length) {
      gridEl.innerHTML = `
        <div style="grid-column:1/-1;text-align:center;padding:60px 20px;">
          <p style="color:#6B5B55;font-size:1rem;">No products in this category yet.</p>
          <a href="#" data-whatsapp class="btn-primary" style="margin-top:16px;border-radius:2px;display:inline-block;">
            Inquire on WhatsApp
          </a>
        </div>`;
      renderStoreInfo();
      return;
    }

    gridEl.innerHTML = filtered.map((p, i) => {
      if (p.isPlaceholder) {
        return `
          <div class="product-card fade-up stagger-${Math.min((i % 6) + 1, 6)}">
            <div class="img-placeholder ${p.imgClass}"
                 style="height:240px;width:100%;"
                 aria-label="${p.title} — placeholder">
              <div style="text-align:center;padding:16px;">
                <div style="font-size:3rem;margin-bottom:6px;">${p.icon}</div>
                <span style="color:rgba(255,255,255,0.5);font-size:10px;text-transform:uppercase;letter-spacing:1.5px;">View Category</span>
              </div>
            </div>
            <div style="padding:16px;">
              <h4 style="font-family:'Playfair Display',serif;font-size:1rem;font-weight:600;color:#2C1810;margin-bottom:6px;">${p.title}</h4>
              <p style="font-size:0.78rem;color:#6B5B55;margin-bottom:10px;line-height:1.5;">${p.description}</p>
              <div style="display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:8px;">
                <span class="price-tag" style="font-size:0.82rem;">${p.price}</span>
                <button onclick="inquireProduct('${p.title.replace(/'/g, "\\'")}')"
                        class="btn-primary"
                        style="font-size:0.72rem;padding:7px 12px;border-radius:2px;">
                  Inquire
                </button>
              </div>
            </div>
          </div>`;
      }
      return `
        <div class="product-card fade-up stagger-${Math.min((i % 6) + 1, 6)}">
          ${p.img
            ? `<div style="position:relative;">
                ${p.badge ? `<span class="badge" style="position:absolute;top:12px;left:12px;z-index:1;">${p.badge}</span>` : ''}
                <img data-src="${p.img}" alt="${p.title}" class="w-full object-cover" style="height:260px;" loading="lazy">
              </div>`
            : `<div class="img-placeholder img-placeholder-featured"
                   style="height:260px;width:100%;position:relative;"
                   aria-label="${p.title} — product image">
                ${p.badge ? `<span class="badge" style="position:absolute;top:12px;left:12px;">${p.badge}</span>` : ''}
                <div style="text-align:center;padding:12px;margin-top:28px;">
                  <span style="font-size:1.8rem;">🛍️</span>
                </div>
              </div>`
          }
          <div style="padding:16px;">
            <p style="font-size:0.7rem;color:#A8843D;font-weight:700;text-transform:uppercase;letter-spacing:0.8px;margin-bottom:4px;">${p.categoryName}</p>
            <h4 style="font-family:'Playfair Display',serif;font-size:0.95rem;font-weight:600;color:#2C1810;margin-bottom:10px;line-height:1.3;">${p.title}</h4>
            <div style="display:flex;align-items:center;justify-content:space-between;">
              <span class="price-tag">${p.price}</span>
              <button onclick="inquireProduct('${p.title.replace(/'/g, "\\'")}')"
                      class="btn-primary"
                      style="font-size:0.72rem;padding:7px 12px;border-radius:2px;">
                Inquire
              </button>
            </div>
          </div>
        </div>`;
    }).join('');

    // Re-run animations and lazy load for newly rendered content
    initScrollAnimations();
    initLazyLoad();
    renderStoreInfo(); // update data-whatsapp links
  }

  // Build filter buttons
  filtersEl.innerHTML = `
    <button class="filter-tab active" data-filter="all">All Collections</button>
    ${SHOP_DATA.categories.map(c =>
      `<button class="filter-tab" data-filter="${c.id}">${c.name}</button>`
    ).join('')}
  `;

  filtersEl.querySelectorAll('.filter-tab').forEach(btn => {
    btn.addEventListener('click', () => {
      filtersEl.querySelectorAll('.filter-tab').forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
      activeFilter = btn.dataset.filter;
      renderGrid(activeFilter);
    });
  });

  // Activate filter from URL hash (e.g. products.html#sarees)
  const hash = window.location.hash.replace('#', '');
  if (hash && SHOP_DATA.categories.find(c => c.id === hash)) {
    activeFilter = hash;
    const tab = filtersEl.querySelector(`[data-filter="${hash}"]`);
    if (tab) {
      filtersEl.querySelectorAll('.filter-tab').forEach(b => b.classList.remove('active'));
      tab.classList.add('active');
    }
  }

  renderGrid(activeFilter);
}

// ============================================================
// POPULATE — CONTACT FORM CATEGORY DROPDOWN
// ============================================================
function populateCategoryDropdown() {
  const sel = document.getElementById('form-category');
  if (!sel) return;
  SHOP_DATA.categories.forEach(cat => {
    const opt = document.createElement('option');
    opt.value       = cat.id;
    opt.textContent = cat.name;
    sel.appendChild(opt);
  });
}

// ============================================================
// PRODUCT INQUIRY (called from inline onclick)
// ============================================================
function inquireProduct(title) {
  const msg =
    `Hello! I'm interested in *${title}* from Match N Design by Minal.\n` +
    `Could you please share details, availability, and pricing? 🙏`;
  window.open(buildWhatsAppLink(msg), '_blank', 'noopener,noreferrer');
}

// ============================================================
// INIT — runs on every page
// ============================================================
document.addEventListener('DOMContentLoaded', () => {
  initNavbar();
  renderStoreInfo();
  renderCategories();
  renderFeatured();
  renderTestimonials();
  renderFeatures();
  renderProductsPage();
  populateCategoryDropdown();

  // Delay animations slightly so layout is settled
  requestAnimationFrame(() => {
    initScrollAnimations();
    initBackToTop();
    initContactForm();
    initLazyLoad();
  });
});
